  insert into public.listings (title, category, city, price, description, image_url, contact_email, contact_phone, user_id) values
  ('Mercedes E-Class գովազդային տարածք', 'cars', 'Yerevan', 85, 'Օրական մեկնում է Երևանի կենտրոնով, բարձր տեսանելիություն։ Պրեմիում սեդան, հնարավոր է ամբողջական փաթաթում կամ դռների պանելներ։', 'https://images.unsplash.com/photo-1618843479313-40f8afb4b4d8?w=800&q=80', 'owner1@mail.com', '+37490000001', uid),
  ('Toyota Prius ավտոմեքենայի գովազդ', 'cars', 'Yerevan', 45, 'Էկոլոգիчески մաքուր Prius գլխավոր պողոտաներում։ Հարմար ապրանքանիշի ճանաչելիության և կանաչ արշավների համար։', 'https://images.unsplash.com/photo-1511919884226-fd3cad34687c?w=800&q=80', 'owner2@mail.com', '+37490000002', uid),
  ('Շենքի պատի բաների տարածք', 'walls', 'Vanadzor', 120, 'Խոշոր պատ գլխավոր ճանապարհի դիմաց։ Հարմար բիլբորդների և ապրանքանիշի արշավների համար։ Բարձր տեսանելիություն։', 'https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?w=800&q=80', 'owner3@mail.com', '+37490000003', uid),
  ('Խանութի ցուցափեղկի գովազդային տեղ', 'shop_windows', 'Gyumri', 75, 'Գտնվում է մովակ փողոցում, ուժեղ հետիոտնային հոսքով։ Փողոցի մակարդակի ցուցափեղկ։', 'https://images.unsplash.com/photo-1441986300917-64674bd600d8?w=800&q=80', 'owner4@mail.com', '+37490000004', uid),
  ('Քաղաքային փողոցի պատի գովազդ', 'walls', 'Yerevan', 95, 'Հանրահայտ առևտրի գոտի, մոտակայքում բազմաթիվ տեղական բիզնեսներ։ Մեծ տեսանելիություն ավտոմեքենաների և հետիոտների համար։', 'https://images.unsplash.com/photo-1518780664697-55e3ad937233?w=800&q=80', 'owner5@mail.com', '+37490000005', uid),
  ('Առաքման սկուտերի գովազդային տարածք', 'cars', 'Yerevan', 38, 'Սկուտեր օրական առաքումների համար քաղաքի կենտրոնում։ Բարձր հոսք ունեցող մարշրուտ, հարմար տեղական ապրանքանիշների համար։', 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=800&q=80', 'owner6@mail.com', '+37490000006', uid),
  ('Պատշգամբի բաների գովազդ', 'other', 'Dilijan', 55, 'Պատշգամբ գլխավոր փողոցի դիմաց։ սեզոնային զբոսաշրջիկների հոսք և տեղական տեսանելիություն։', 'https://images.unsplash.com/photo-1497366216548-37526070297c?w=800&q=80', 'owner7@mail.com', '+37490000007', uid),
  ('Hyundai Tucson SUV-ի գովազդային տարածք', 'cars', 'Abovyan', 62, 'SUV խոշոր կարոսերիչներով։ Օրական մեկնում է մայրուղով և քաղաքային մարշրուտներով։', 'https://images.unsplash.com/photo-1609521263047-f8f205293f24?w=800&q=80', 'owner8@mail.com', '+37490000008', uid),
  ('Անկյունային շենքի ճակատ', 'buildings', 'Yerevan', 165, 'Անկյունային շենք մովակ խաչմերուկում։ Առավելագույն տեսանելիություն ապրանքանիշների համար։', 'https://images.unsplash.com/photo-1545324418-cc1a3fa10c00?w=800&q=80', 'owner9@mail.com', '+37490000009', uid),
